const cartasEterrion = [
  // --- CARTAS COMUNES (01 - 50) ---
  { id: "RdC 01", nombre: "Elara", reino: "Ventaris", clase: "Sacerdote", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Ráfaga", tecnica_2: "", expl_tec_1: "Otorga Veloz al siguiente héroe aliado cuando entre en juego.", expl_tec_2: "", lore: "Noble y astuta, Elara busca el bien de Ventaris por medio de su destino. Sus ojos revelan la carga de liderar en tiempos oscuros.", img: "1.png" },
  { id: "RdC 02", nombre: "Aqualis", reino: "Mo'lah", clase: "Guardián", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Calma de la profundidad", tecnica_2: "", expl_tec_1: "Pon tu última carta del cementerio en el mazo y revuelve.", expl_tec_2: "", lore: "Muchos lo han descrito como una criatura marina majestuosa con escamas que brillan como las olas del mar bajo el sol.", img: "2.png" },
  { id: "RdC 03", nombre: "Volt", reino: "Ventaris", clase: "Sacerdote", fuerza: 8, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Tormenta mental", tecnica_2: "", expl_tec_1: "Hunde al último enemigo que entró al campo de batalla.", expl_tec_2: "", lore: "Un erudito desde la cuna. Su presencia está rodeada por un aura de energía mientras que su voz resuena como un fuerte trueno a la distancia.", img: "3.png" },
  { id: "RdC 04", nombre: "Glimrick", reino: "Aric", clase: "Gnomo", fuerza: 1, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "¡Te juro que es verdad!", tecnica_2: "", expl_tec_1: "Glimrick se intercambia con un enemigo que esté dentro del campo de batalla y ambos quedan silenciaos.", expl_tec_2: "", lore: "Enano ingenioso y astuto que se las arregla para obtener fama por medio de las mentiras y los cuentos.", img: "4.png" },
  { id: "RdC 05", nombre: "Anaira", reino: "Mo'lah", clase: "Pirata", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "El Espuma Negra", tecnica_2: "", expl_tec_1: "Cada vez que Anaira derrote a un enemigo más débil en batalla, gana +I de fuerza.", expl_tec_2: "", lore: "Su naturaleza libre y salvaje la han forjado como una de las piratas más nobles y despiadadas de Mo'lah.", img: "5.png" },
  { id: "RdC 06", nombre: "Granvar", reino: "Aric", clase: "Golem", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Uno con la roca", tecnica_2: "", expl_tec_1: "Otorga +3 de fuerza a un aliado a elección.", expl_tec_2: "", lore: "Su nacimiento fue un milagro para todos los golems de las altas montañas. Su esencia latente es el orgullo de su clan.", img: "6.png" },
  { id: "RdC 07", nombre: "Aerinthos", reino: "Aystar", clase: "Guardián", fuerza: 8, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Sombra de la ventisca", tecnica_2: "", expl_tec_1: "Maldice al último enemigo que entró al campo de batalla con -3 de fuerza.", expl_tec_2: "", lore: "Con los ojos brillantes como escarchas; su presencia calma y serena como la nieve, pero feroz como una avalancha.", img: "7.png" },
  { id: "RdC 08", nombre: "Kaira", reino: "Cahl'ama", clase: "Guardián", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Arenas del tiempo", tecnica_2: "", expl_tec_1: "Devuelve a la mano todas las cartas que estén silenciadas en el campo de batalla.", expl_tec_2: "", lore: "Tratada con respeto, Kaira solo quiere que la paz vuelva a su pueblo dominado por las arenas. Para muchos ella representa la libertad y la esperanza.", img: "8.png" },
  { id: "RdC 09", nombre: "Drakar", reino: "Zelphyd", clase: "Guerrero", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Manos manchadas", tecnica_2: "", expl_tec_1: "Maldice a un enemigo a elección con -2 de fuerza.", expl_tec_2: "", lore: "Con una armadura manchada por la sangre de sus enemigos, empuña la espada de la noche, la que un día empuñaron los primeros sanguinarios.", img: "9.png" },
  { id: "RdC 10", nombre: "Grimor", reino: "Zelphyd", clase: "Sombrío", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Aún no es tu hora", tecnica_2: "", expl_tec_1: "Revive al último enemigo que cayó al cementerio para ponerlo en tu campo de batalla.", expl_tec_2: "", lore: "Nadie sabe como llegó al cementerio ... pero con la muerte de su lado, empuña su pala con reverencia hacia los difuntos.", img: "10.png" },
  { id: "RdC 11", nombre: "Embera", reino: "Ignis", clase: "Brujo", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Llama vital", tecnica_2: "", expl_tec_1: "Otorga +I de vida al estratega.", expl_tec_2: "", lore: "Con ojos que resplandecen como brasas ardientes, su presencia emana calor y su mirada refleja la sabiduría de las llamas.", img: "11.png" },
  { id: "RdC 12", nombre: "Marina", reino: "Aystar", clase: "Bestia", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "¡Hora feliz!", tecnica_2: "", expl_tec_1: "Llama al campo de batalla a la primera carta de tu mazo.", expl_tec_2: "", lore: "Una figura materna para algunos, para otros la fuente de sus bebidas. Viste un delantal con las inscripciones antiguas del verano congelado.", img: "12.png" },
  { id: "RdC 13", nombre: "Ealdred", reino: "Elenaria", clase: "Guerrero", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Fortaleza de luminis", tecnica_2: "", expl_tec_1: "Otorga +I de fuerza a un aliado a elección.", expl_tec_2: "", lore: "Con una armadura reluciente y una actitud ganadora, es la personificación de la valentía y lealtad en tiempos de adversidad.", img: "13.png" },
  { id: "RdC 14", nombre: "Lyra", reino: "Elenaria", clase: "Guerrero", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Luz de Elenaria", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla, ciega al enemigo más fuerte.", expl_tec_2: "", lore: "Con su armadura plateada encarna la valentía y determinación en los tiempos de guerra. Su espada reluce como la esperanza que representa.", img: "14.png" },
  { id: "RdC 15", nombre: "Dr. Flamigato", reino: "Ignis", clase: "Erudito", fuerza: 2, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "9 de cada 10 flamas", tecnica_2: "", expl_tec_1: "Maldice a un enemigo a elección con -5 de fuerza.", expl_tec_2: "", lore: "Prrr … La ciencia y el avance tecnológico.", img: "15.png" },
  { id: "RdC 16", nombre: "Melthok", reino: "Daelum", clase: "Mutante", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Consumo vital", tecnica_2: "", expl_tec_1: "Cuando muere, elimina a un enemigo a elección.", expl_tec_2: "", lore: "Nadie sabe cómo es que cobró vida. Se desliza con malevolencia, saciando su apetito por la magia, convirtiéndolo en una amenaza para los reinos.", img: "16.png" },
  { id: "RdC 17", nombre: "Thalron", reino: "Daelum", clase: "Erudito", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Esto dolerá", tecnica_2: "", expl_tec_1: "Silencia al último enemigo que entró al campo de batalla.", expl_tec_2: "", lore: "Famoso por ser el alquimista de Daelum. Su esencia nocturna y su poca compasión por los seres vivos, lo enorgullece y lo motiva.", img: "17.png" },
  { id: "RdC 18", nombre: "Azuril", reino: "Cahl'ama", clase: "Bestia", fuerza: 9, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Terror de las dunas", tecnica_2: "", expl_tec_1: "Otorga Dominante a un aliado a elección.", expl_tec_2: "", lore: "El terror constante en las afueras de la ciudadela. Los ancianos cuentan la leyenda de la gran serpiente azul, temida y evitada por generaciones.", img: "18.png" },
  { id: "RdC 19", nombre: "Selene", reino: "Breesh", clase: "Elfo", fuerza: 2, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Naturaleza infinita", tecnica_2: "", expl_tec_1: "Revive a un aliado a elección y ponlo en tu campo de batalla.", expl_tec_2: "", lore: "Una elfa sin igual de aspecto sereno que manifiesta la paz del bosque de Verd en cada gesto y palabra que brinda.", img: "19.png" },
  { id: "RdC 20", nombre: "Kael", reino: "Breesh", clase: "Guardián", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Sombra dorada", tecnica_2: "", expl_tec_1: "Tu rival no puede defender su ataque con cartas con un nivel de fuerza de 5 o más.", expl_tec_2: "", lore: "Un mono ágil de pelaje dorado, se desliza entre las hojas con destreza, protegiendo los bosques de Breesh.", img: "20.png" },
  { id: "RdC 21", nombre: "Irian", reino: "Daelum", clase: "Mutante", fuerza: 1, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Instinto de locura", tecnica_2: "", expl_tec_1: "Irian gana +2 de fuerza por cada carta que se juegue en tu campo de batalla desde que entre en juego.", expl_tec_2: "", lore: "Una criatura inocente que por sobrevivir a la locura del reino, tuvo que adaptarse hasta perder su nobleza.", img: "21.png" },
  { id: "RdC 22", nombre: "Seom", reino: "Aystar", clase: "Bestia", fuerza: 8, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Ternura barbárica", tecnica_2: "", expl_tec_1: "El enemigo con menor nivel de fuerza no puede atacar mientras Seom este en el campo de batalla.", expl_tec_2: "", lore: "Nació fuera del nido, lejano a su hogar. Esta criatura fue adoptada por un pueblo en que la fuerza de la nieve forma a los mejores guerreros del reino.", img: "22.png" },
  { id: "RdC 23", nombre: "Willow", reino: "Breesh", clase: "Explorador", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "¡La aventura nos aguarda!", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla. Llama a la batalla la primera carta de tu mazo, pero silenciada.", expl_tec_2: "", lore: "Una exploradora innata que desde pequeña empezó a buscar las mejores flores y rutas para el bien de su pueblo.", img: "23.png" },
  { id: "RdC 24", nombre: "Qu'yen", reino: "Cahl'ama", clase: "Golem", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Radar tectónico", tecnica_2: "", expl_tec_1: "Qu'yen puede defender los ataques de los enemigos con Sigilo.", expl_tec_2: "", lore: "Un escarabajo hecho de rocas que espera a los comerciantes bajo las arenas para así alimentarse de su mercancía y de ellos.", img: "24.png" },
  { id: "RdC 25", nombre: "Meaf", reino: "Ventaris", clase: "Guardián", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Misericordia", tecnica_2: "", expl_tec_1: "Iguala tus puntos de vida con los de tu rival.", expl_tec_2: "", lore: "Meaf siempre ha tenido la curiosidad de saber como las aldeas se construyeron entre las rocas flotantes que anteriormente eran nubes y su hogar.", img: "25.png" },
  { id: "RdC 26", nombre: "Enater", reino: "Ignis", clase: "Brujo", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Protección ígnea", tecnica_2: "", expl_tec_1: "El enemigo con el mayor nivel de fuerza no puede bloquear mientras Enater esté en el campo de batalla.", expl_tec_2: "", lore: "Para su clan, la fuerza del fuego es insaciable y el control de este es la diferencia entre un esclavo y un lord.", img: "26.png" },
  { id: "RdC 27", nombre: "Mire", reino: "Elenaria", clase: "Explorador", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Alas de rubí", tecnica_2: "", expl_tec_1: "Mientras tengas 3 o más aliados con el mismo nivel de fuerza en el campo de batalla, tu oponente no puede defenderse.", expl_tec_2: "", lore: "Mientras algunos batallan en el suelo con armas, Mire comanda el ataque desde los cielos sobre Aniura, representando la esperanza de la victoria.", img: "27.png" },
  { id: "RdC 28", nombre: "Lena", reino: "Mo'lah", clase: "Domador", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Marea alta", tecnica_2: "", expl_tec_1: "Cuando Lena es derrotada toma el control de 2 enemigos con un nivel de fuerza de 6 o menos.", expl_tec_2: "", lore: "La pesca y el agua es la felicidad para el pueblo de Varas, y sobre todo para Lena quien sueña con atrapar a la Gran Masiusta en el mar.", img: "28.png" },
  { id: "RdC 29", nombre: "Barum", reino: "Zelphyd", clase: "Guerrero", fuerza: 8, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Control de batalla", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla, derrota a todos los enemigos con un nivel de fuerza de 4 o menos.", expl_tec_2: "", lore: "Sacrificó todo lo que tenía para salvar a su familia y aun así fue traicionado. Ahora como un general de Zelphyd hará lo imposible para que sufran como él.", img: "29.png" },
  { id: "RdC 30", nombre: "Floots", reino: "Aric", clase: "Bestia", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Excavación profunda", tecnica_2: "", expl_tec_1: "Cuando Floots entra al campo de batalla, todos los hitos en juego son destruidos y pasan al cementerio.", expl_tec_2: "", lore: "El mayor de 24 hermanos, es uno de los excavadores más rápidos para encontrar las piedras preciosas sin importar el peligro de los derrumbes que se produzcan.", img: "30.png" },
  { id: "RdC 31", nombre: "Aereon", reino: "Ventaris", clase: "Dragón", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Viento fulminante", tecnica_2: "", expl_tec_1: "Cuando es derrotada, derrota a todas los rivales con 7 de fuerza o más", expl_tec_2: "", lore: "Debido a su presencia, las aurai evitan regresar a las antiguas ruinas del Templo de los Vientos ... aún se puede escuchar los anhelantes suspiros por regresar al templo.", img: "31.png" },
  { id: "RdC 32", nombre: "Bjorn", reino: "Aystar", clase: "Guerrero", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "¡Luchar por Vargheim!", tecnica_2: "", expl_tec_1: "Tus aliados tienen +1 de fuerza por cada aliado de Aystar en tu campo de batalla.", expl_tec_2: "", lore: "Cuando la nieve se tiñe de acero y los cuernos de guerra retumban, Bjorn avanza golpeando su escudo y ruge: -'¡Vargheim no retrocede ... VARGHEIM DEVORA!'", img: "32.png" },
  { id: "RdC 33", nombre: "Valris", reino: "Cahl'ama", clase: "Sacerdote", fuerza: 2, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Sinergia de Valris", tecnica_2: "", expl_tec_1: "Si en el último turno perdiste una vida, ganas 3 puntos de vida", expl_tec_2: "", lore: "Nacido bajo el tercer eclipse del desierto, su magia honra pactos antiguos y como príncipe hechicero de las arenas, su poder no conquista: purifica, preserva y transforma.", img: "33.png" },
  { id: "RdC 34", nombre: "Mix", reino: "Daelum", clase: "Vampiro", fuerza: 2, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Ultimo hurto", tecnica_2: "", expl_tec_1: "Cuando es derrotada, roba una carta al azar de tu rival", expl_tec_2: "", lore: "Mix destila toxinas que alteran la voluntad y la carne mientras que su habilidad libera vapores encantados que confunden, seducen o destruyen según su capricho.", img: "34.png" },
  { id: "RdC 35", nombre: "Varkhan", reino: "Zelphyd", clase: "Vampiro", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Flujo sanguíneo", tecnica_2: "", expl_tec_1: "Si hay un sacerdote en tu campo de batalla tu rival pierde un punto de vida y tú ganas un punto de vida", expl_tec_2: "", lore: "El ascenso al poder suele estar sembrado de atrocidades, pero también hay belleza en el caos ... solo debes aprender a apreciarla.", img: "35.png" },
  { id: "RdC 36", nombre: "Celeste", reino: "Elenaria", clase: "Guerrero", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Rito del Ocaso", tecnica_2: "", expl_tec_1: "Tu rival intercambia su cementerio por su mazo y su mazo por su cementerio (Esta técnica tiene efecto si hay un sacerdote y un guerrero en el campo de batalla)", expl_tec_2: "", lore: "Nacida en las sombras del reino oscuro, fue la primera en desafiar su destino y abrazar la luz de Elenaria. -'Si la oscuridad nos creó, que la luz vea lo que somos capaces de deshacer'.", img: "36.png" },
  { id: "RdC 37", nombre: "Meleste", reino: "Elenaria", clase: "Sacerdote", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Rito del Alba", tecnica_2: "", expl_tec_1: "Tu intercambias tu cementerio por tu mazo y tu mazo por tu cementerio (Esta técnica tiene efecto si hay un guardián y un guerrero en el campo de batalla)", expl_tec_2: "", lore: "Criada en el mismo abismo que su hermana, siguió el rastro de luz que Celeste abrió en la oscuridad. -'Hermana, donde tu espada abre camino, mi magia lo ilumina o lo consume'.", img: "37.png" },
  { id: "RdC 38", nombre: "Talina", reino: "Ignis", clase: "Explorador", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Fiesta explosiva", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla puedes ver las cartas de tu adversario y poner una en su mazo para que revuelva.", expl_tec_2: "", lore: "'¡Si no explota en colores, no cuenta como victoria!' -Talina, exploradora alocada.", img: "38.png" },
  { id: "RdC 39", nombre: "Kraivus", reino: "Zelphyd", clase: "Guardián", fuerza: 8, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Última voluntad", tecnica_2: "", expl_tec_1: "Si lo juegas puedes decidir perder 1 punto de vida, si lo haces Kraivus obtiene Furia, Desafío, Firmeza", expl_tec_2: "", lore: "En sus ojos están grabados todos los caminos trazados por la antigua orden de la luz, pero el dolor y la deshonra nunca desaparecerán.", img: "39.png" },
  { id: "RdC 40", nombre: "Nairus", reino: "Cahl'ama", clase: "Guardián", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Silencio sombrío", tecnica_2: "", expl_tec_1: "Juega una carta con una técnica que diga 'Derrotada' del cementerio de cualquier jugador.", expl_tec_2: "", lore: "Fue enterrado con mil nombres y mil maldiciones, pero las almas no lo olvidaron. Ahora, camina otra vez por el desierto, invocando a los que murieron ... y absorbiendo a los que lo negaron alguna vez.", img: "40.png" },
  { id: "RdC 41", nombre: "Ralya", reino: "Breesh", clase: "Hada", fuerza: 1, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Susurro valeroso", tecnica_2: "", expl_tec_1: "Cuando es derrotada, si no hay más aliados en tu campo de batalla, derrota a todos los enemigos de tu rival", expl_tec_2: "", lore: "Guardiana del Bosque de los Ecos. Su magia florece al ritmo de los secretos que susurra la luz entre los árboles. Protege los recuerdos olvidados, convirtiéndolos en hechizos que sanan o condenan.", img: "41.png" },
  { id: "RdC 42", nombre: "Nelieri", reino: "Mo'lah", clase: "Pirata", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Copia pirata", tecnica_2: "", expl_tec_1: "Puedes revelar una carta de tu mano. Si lo haces, copia su técnica.", expl_tec_2: "", lore: "Criada entre pólvora y traiciones, Nelieri Drakborn heredó el timón ensangrentado de su padre ... pero no su alma. Ahora surca mares con una sed de conquista y es temida por quienes aún recuerdan su nombre como la Tempestad Roja.", img: "42.png" },
  { id: "RdC 43", nombre: "Nasin", reino: "Daelum", clase: "Erudito", fuerza: 7, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Grieta de Poibrik", tecnica_2: "", expl_tec_1: "Un rival descarta una carta. Si la carta tiene 4 de fuerza o más, el rival pierde 1 punto de vida", expl_tec_2: "", lore: "'¡No es veneno si te da superpoderes ... durante los primeros cinco minutos!' -Nasin, aprendiz rebelde de Laor.", img: "43.png" },
  { id: "RdC 44", nombre: "Kora", reino: "Breesh", clase: "Titán", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Indómito de Kora", tecnica_2: "", expl_tec_1: "Puedes descartar una carta de tu mano. Derrota todos los enemigos que compartan una habilidad con esta carta.", expl_tec_2: "", lore: "Un antiguo titán errante que protege los secretos de los bosques del reino. Su núcleo, codiciado por muchos, se dice que alberga el corazón de una diosa caída del Bosque de los Ecos.", img: "44.png" },
  { id: "RdC 45", nombre: "Marcus", reino: "Ignis", clase: "Explorador", fuerza: 6, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Inversión de fuego", tecnica_2: "", expl_tec_1: "Cuando Marcus gana una batalla descarta una carta de la mano de tu rival (Se activa solo si hay dos o más guerreros en el campo de batalla)", expl_tec_2: "", lore: "Aprendió a domar el fuego cuando su maestro lo abandono en el primer coliseo que vio. Ahora combate en arenas prohibidas, buscando reliquias que solo se revelan entre llamas y sangre.", img: "45.png" },
  { id: "RdC 46", nombre: "Tao'ai", reino: "Aystar", clase: "Bestia", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Furia salvaje", tecnica_2: "", expl_tec_1: "Cuando atacas, derrota a todos los rivales que tengan Sigilo y/o Letal", expl_tec_2: "", lore: "'¡Nadie volverá a encadenarme, nadie volverá a abandonarme y nadie volverá vivo!' -Tao'ai.", img: "46.png" },
  { id: "RdC 47", nombre: "Diana", reino: "Ventaris", clase: "Invocador", fuerza: 5, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Favor del viento", tecnica_2: "", expl_tec_1: "Cuando ataca, devuelve una carta de tu cementerio a tu mano", expl_tec_2: "", lore: "Por miedo, fue desterrada a las gargantas ventosas del Abismo del Sur ... En ese lugar solitario, Diana no se debilitó: creció.", img: "47.png" },
  { id: "RdC 48", nombre: "Kaelor", reino: "Aric", clase: "Golem", fuerza: 1, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Presión rocosa", tecnica_2: "", expl_tec_1: "Cuando atacas tienes +8 de fuerza en este turno", expl_tec_2: "", lore: "'Tallado por manos que ya no existen, guarda en su corazón furia tectónica y luz prestada'. -Lavinia.", img: "48.png" },
  { id: "RdC 49", nombre: "Lit", reino: "Mo'lah", clase: "Invocador", fuerza: 3, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Retribución de Lit", tecnica_2: "", expl_tec_1: "Cuando es derrotada en combate, roba dos cartas al azar de la mano de tu rival", expl_tec_2: "", lore: "'Si temes ahogarte, retrocede ... mis criaturas no distinguen amigo de intruso'. Lit, la invocadora de Silente, canaliza las aguas antiguas que responden solo a su voluntad.", img: "49.png" },
  { id: "RdC 50", nombre: "Giaref", reino: "Aric", clase: "Guerrero", fuerza: 4, rareza: "Común", habilidad_1: "", habilidad_2: "", tecnica_1: "Hacha de acero audaz", tecnica_2: "", expl_tec_1: "Si ganas la batalla, juegas otro turno después de este", expl_tec_2: "", lore: "Dicen que su fuerza no viene del cuerpo, sino de cada guerra que ha sobrevivido sin rendirse.", img: "50.png" },

  // --- CARTAS RARAS (51 - 100) ---
  { id: "RdC 51", nombre: "Elara", reino: "Ventaris", clase: "Sacerdote", fuerza: 5, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Ráfaga", tecnica_2: "", expl_tec_1: "Otorga Veloz al siguiente héroe aliado cuando entre en juego.", expl_tec_2: "", lore: "Noble y astuta, Elara busca el bien de Ventaris por medio de su destino. Sus ojos revelan la carga de liderar en tiempos oscuros.", img: "51.png" },
  { id: "RdC 52", nombre: "Aqualis", reino: "Mo'lah", clase: "Guardián", fuerza: 4, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Calma de la profundidad", tecnica_2: "", expl_tec_1: "Pon tu última carta del cementerio en el mazo y revuelve.", expl_tec_2: "", lore: "Muchos lo han descrito como una criatura marina majestuosa con escamas que brillan como las olas del mar bajo el sol.", img: "52.png" },
  { id: "RdC 53", nombre: "Volt", reino: "Ventaris", clase: "Sacerdote", fuerza: 8, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Tormenta mental", tecnica_2: "", expl_tec_1: "Hunde al último enemigo que entró al campo de batalla.", expl_tec_2: "", lore: "Un erudito desde la cuna. Su presencia está rodeada por un aura de energía mientras que su voz resuena como un fuerte trueno a la distancia.", img: "53.png" },
  { id: "RdC 54", nombre: "Glimrick", reino: "Aric", clase: "Gnomo", fuerza: 1, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "¡Te juro que es verdad!", tecnica_2: "", expl_tec_1: "Glimrick se intercambia con un enemigo que esté dentro del campo de batalla y ambos quedan silenciaos.", expl_tec_2: "", lore: "Enano ingenioso y astuto que se las arregla para obtener fama por medio de las mentiras y los cuentos.", img: "54.png" },
  { id: "RdC 55", nombre: "Anaira", reino: "Mo'lah", clase: "Pirata", fuerza: 5, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "El Espuma Negra", tecnica_2: "", expl_tec_1: "Cada vez que Anaira derrote a un enemigo más débil en batalla, gana +I de fuerza.", expl_tec_2: "", lore: "Su naturaleza libre y salvaje la han forjado como una de las piratas más nobles y despiadadas de Mo'lah.", img: "55.png" },
  { id: "RdC 56", nombre: "Granvar", reino: "Aric", clase: "Golem", fuerza: 3, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Uno con la roca", tecnica_2: "", expl_tec_1: "Otorga +3 de fuerza a un aliado a elección.", expl_tec_2: "", lore: "Su nacimiento fue un milagro para todos los golems de las altas montañas. Su esencia latente es el orgullo de su clan.", img: "56.png" },
  { id: "RdC 57", nombre: "Aerinthos", reino: "Aystar", clase: "Guardián", fuerza: 8, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Sombra de la ventisca", tecnica_2: "", expl_tec_1: "Maldice al último enemigo que entró al campo de batalla con -3 de fuerza.", expl_tec_2: "", lore: "Con los ojos brillantes como escarchas; su presencia calma y serena como la nieve, pero feroz como una avalancha.", img: "57.png" },
  { id: "RdC 58", nombre: "Kaira", reino: "Cahl'ama", clase: "Guardián", fuerza: 5, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Arenas del tiempo", tecnica_2: "", expl_tec_1: "Devuelve a la mano todas las cartas que estén silenciadas en el campo de batalla.", expl_tec_2: "", lore: "Tratada con respeto, Kaira solo quiere que la paz vuelva a su pueblo dominado por las arenas. Para muchos ella representa la libertad y la esperanza.", img: "58.png" },
  { id: "RdC 59", nombre: "Drakar", reino: "Zelphyd", clase: "Guerrero", fuerza: 7, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Manos manchadas", tecnica_2: "", expl_tec_1: "Maldice a un enemigo a elección con -2 de fuerza.", expl_tec_2: "", lore: "Con una armadura manchada por la sangre de sus enemigos, empuña la espada de la noche, la que un día empuñaron los primeros sanguinarios.", img: "59.png" },
  { id: "RdC 60", nombre: "Grimor", reino: "Zelphyd", clase: "Sombrío", fuerza: 6, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Aún no es tu hora", tecnica_2: "", expl_tec_1: "Revive al último enemigo que cayó al cementerio para ponerlo en tu campo de batalla.", expl_tec_2: "", lore: "Nadie sabe como llegó al cementerio ... pero con la muerte de su lado, empuña su pala con reverencia hacia los difuntos.", img: "60.png" },
  { id: "RdC 61", nombre: "Embera", reino: "Ignis", clase: "Brujo", fuerza: 7, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Llama vital", tecnica_2: "", expl_tec_1: "Otorga +I de vida al estratega.", expl_tec_2: "", lore: "Con ojos que resplandecen como brasas ardientes, su presencia emana calor y su mirada refleja la sabiduría de las llamas.", img: "61.png" },
  { id: "RdC 62", nombre: "Marina", reino: "Aystar", clase: "Bestia", fuerza: 3, rareza: "Rara", habilidad_1: "Firmeza", habilidad_2: "", tecnica_1: "¡Hora feliz!", tecnica_2: "", expl_tec_1: "Llama al campo de batalla a la primera carta de tu mazo.", expl_tec_2: "", lore: "Una figura materna para algunos, para otros la fuente de sus bebidas. Viste un delantal con las inscripciones antiguas del verano congelado.", img: "62.png" },
  { id: "RdC 63", nombre: "Ealdred", reino: "Elenaria", clase: "Guerrero", fuerza: 7, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Fortaleza de luminis", tecnica_2: "", expl_tec_1: "Otorga +I de fuerza a un aliado a elección.", expl_tec_2: "", lore: "Con una armadura reluciente y una actitud ganadora, es la personificación de la valentía y lealtad en tiempos de adversidad.", img: "63.png" },
  { id: "RdC 64", nombre: "Lyra", reino: "Elenaria", clase: "Guerrero", fuerza: 5, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Luz de Elenaria", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla, ciega al enemigo más fuerte.", expl_tec_2: "", lore: "Con su armadura plateada encarna la valentía y determinación en los tiempos de guerra. Su espada reluce como la esperanza que representa.", img: "64.png" },
  { id: "RdC 65", nombre: "Dr. Flamigato", reino: "Ignis", clase: "Erudito", fuerza: 2, rareza: "Rara", habilidad_1: "Firmeza", habilidad_2: "", tecnica_1: "9 de cada 10 flamas", tecnica_2: "", expl_tec_1: "Maldice a un enemigo a elección con -5 de fuerza.", expl_tec_2: "", lore: "Prrr … La ciencia y el avance tecnológico.", img: "65.png" },
  { id: "RdC 66", nombre: "Melthok", reino: "Daelum", clase: "Mutante", fuerza: 3, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Consumo vital", tecnica_2: "", expl_tec_1: "Cuando muere, elimina a un enemigo a elección.", expl_tec_2: "", lore: "Nadie sabe cómo es que cobró vida. Se desliza con malevolencia, saciando su apetito por la magia, convirtiéndolo en una amenaza para los reinos.", img: "66.png" },
  { id: "RdC 67", nombre: "Thalron", reino: "Daelum", clase: "Erudito", fuerza: 6, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Esto dolerá", tecnica_2: "", expl_tec_1: "Silencia al último enemigo que entró al campo de batalla.", expl_tec_2: "", lore: "Famoso por ser el alquimista de Daelum. Su esencia nocturna y su poca compasión por los seres vivos, lo enorgullece y lo motiva.", img: "67.png" },
  { id: "RdC 68", nombre: "Azuril", reino: "Cahl'ama", clase: "Bestia", fuerza: 9, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Terror de las dunas", tecnica_2: "", expl_tec_1: "Otorga Dominante a un aliado a elección.", expl_tec_2: "", lore: "El terror constante en las afueras de la ciudadela. Los ancianos cuentan la leyenda de la gran serpiente azul, temida y evitada por generaciones.", img: "68.png" },
  { id: "RdC 69", nombre: "Selene", reino: "Breesh", clase: "Elfo", fuerza: 2, rareza: "Rara", habilidad_1: "Toque mortal", habilidad_2: "", tecnica_1: "Naturaleza infinita", tecnica_2: "", expl_tec_1: "Revive a un aliado a elección y ponlo en tu campo de batalla.", expl_tec_2: "", lore: "Una elfa sin igual de aspecto sereno que manifiesta la paz del bosque de Verd en cada gesto y palabra que brinda.", img: "69.png" },
  { id: "RdC 70", nombre: "Kael", reino: "Breesh", clase: "Guardián", fuerza: 4, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Sombra dorada", tecnica_2: "", expl_tec_1: "Tu rival no puede defender su ataque con cartas con un nivel de fuerza de 5 o más.", expl_tec_2: "", lore: "Un mono ágil de pelaje dorado, se desliza entre las hojas con destreza, protegiendo los bosques de Breesh.", img: "70.png" },
  { id: "RdC 71", nombre: "Irian", reino: "Daelum", clase: "Mutante", fuerza: 1, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Instinto de locura", tecnica_2: "", expl_tec_1: "Irian gana +2 de fuerza por cada carta que se juegue en tu campo de batalla desde que entre en juego.", expl_tec_2: "", lore: "Una criatura inocente que por sobrevivir a la locura del reino, tuvo que adaptarse hasta perder su nobleza.", img: "71.png" },
  { id: "RdC 72", nombre: "Seom", reino: "Aystar", clase: "Bestia", fuerza: 8, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Ternura barbárica", tecnica_2: "", expl_tec_1: "El enemigo con menor nivel de fuerza no puede atacar mientras Seom este en el campo de batalla.", expl_tec_2: "", lore: "Nació fuera del nido, lejano a su hogar. Esta criatura fue adoptada por un pueblo en que la fuerza de la nieve forma a los mejores guerreros del reino.", img: "72.png" },
  { id: "RdC 73", nombre: "Willow", reino: "Breesh", clase: "Explorador", fuerza: 5, rareza: "Rara", habilidad_1: "Toque mortal", habilidad_2: "", tecnica_1: "¡La aventura nos aguarda!", tecnica_2: "", expl_tec_1: "Llama a la batalla la primera carta de tu mazo, pero silenciada.", expl_tec_2: "", lore: "Una exploradora innata que desde pequeña empezó a buscar las mejores flores y rutas para el bien de su pueblo.", img: "73.png" },
  { id: "RdC 74", nombre: "Qu'yen", reino: "Cahl'ama", clase: "Golem", fuerza: 4, rareza: "Rara", habilidad_1: "Firmeza", habilidad_2: "", tecnica_1: "Radar tectónico", tecnica_2: "", expl_tec_1: "Qu'yen puede defender los ataques de los enemigos con Sigilo.", expl_tec_2: "", lore: "Un escarabajo hecho de rocas que espera a los comerciantes bajo las arenas para así alimentarse de su mercancía y de ellos.", img: "74.png" },
  { id: "RdC 75", nombre: "Meaf", reino: "Ventaris", clase: "Guardián", fuerza: 6, rareza: "Rara", habilidad_1: "Toque mortal", habilidad_2: "", tecnica_1: "Misericordia", tecnica_2: "", expl_tec_1: "Iguala tus puntos de vida con los de tu rival.", expl_tec_2: "", lore: "Meaf siempre ha tenido la curiosidad de saber como las aldeas se construyeron entre las rocas flotantes que anteriormente eran nubes y su hogar.", img: "75.png" },
  { id: "RdC 76", nombre: "Enater", reino: "Ignis", clase: "Brujo", fuerza: 6, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Protección ígnea", tecnica_2: "", expl_tec_1: "El enemigo con el mayor nivel de fuerza no puede bloquear mientras Enater esté en el campo de batalla.", expl_tec_2: "", lore: "Para su clan, la fuerza del fuego es insaciable y el control de este es la diferencia entre un esclavo y un lord.", img: "76.png" },
  { id: "RdC 77", nombre: "Mire", reino: "Elenaria", clase: "Explorador", fuerza: 7, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Alas de rubí", tecnica_2: "", expl_tec_1: "Mientras tengas 3 o más aliados con el mismo nivel de fuerza en el campo de batalla, tu oponente no puede defenderse.", expl_tec_2: "", lore: "Mientras algunos batallan en el suelo con armas, Mire comanda el ataque desde los cielos sobre Aniura, representando la esperanza de la victoria.", img: "77.png" },
  { id: "RdC 78", nombre: "Lena", reino: "Mo'lah", clase: "Domador", fuerza: 6, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Marea alta", tecnica_2: "", expl_tec_1: "Cuando Lena es derrotada toma el control de 2 enemigos con un nivel de fuerza de 6 o menos.", expl_tec_2: "", lore: "La pesca y el agua es la felicidad para el pueblo de Varas, y sobre todo para Lena quien sueña con atrapar a la Gran Masiusta en el mar.", img: "78.png" },
  { id: "RdC 79", nombre: "Barum", reino: "Zelphyd", clase: "Guerrero", fuerza: 8, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Control de batalla", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla, derrota a todos los enemigos con un nivel de fuerza de 4 o menos.", expl_tec_2: "", lore: "Sacrificó todo lo que tenía para salvar a su familia y aun así fue traicionado. Ahora como un general de Zelphyd hará lo imposible para que sufran como él.", img: "79.png" },
  { id: "RdC 80", nombre: "Floots", reino: "Aric", clase: "Bestia", fuerza: 3, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Excavación profunda", tecnica_2: "", expl_tec_1: "Cuando Floots entra al campo de batalla, todos los hitos en juego son destruidos y pasan al cementerio.", expl_tec_2: "", lore: "El mayor de 24 hermanos, es uno de los excavadores más rápidos para encontrar las piedras preciosas sin importar el peligro de los derrumbes que se produzcan.", img: "80.png" },
  { id: "RdC 81", nombre: "Aereon", reino: "Ventaris", clase: "Dragón", fuerza: 7, rareza: "Rara", habilidad_1: "Firmeza", habilidad_2: "", tecnica_1: "Viento fulminante", tecnica_2: "", expl_tec_1: "Cuando es derrotada, derrota a todas los rivales con 7 de fuerza o más", expl_tec_2: "", lore: "Debido a su presencia, las aurai evitan regresar a las antiguas ruinas del Templo de los Vientos ... aún se puede escuchar los anhelantes suspiros por regresar al templo.", img: "81.png" },
  { id: "RdC 82", nombre: "Bjorn", reino: "Aystar", clase: "Guerrero", fuerza: 6, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "¡Luchar por Vargheim!", tecnica_2: "", expl_tec_1: "Tus aliados tienen +1 de fuerza por cada aliado de Aystar en tu campo de batalla.", expl_tec_2: "", lore: "Cuando la nieve se tiñe de acero y los cuernos de guerra retumban, Bjorn avanza golpeando su escudo y ruge: -'¡Vargheim no retrocede ... VARGHEIM DEVORA!'", img: "82.png" },
  { id: "RdC 83", nombre: "Valris", reino: "Cahl'ama", clase: "Sacerdote", fuerza: 2, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Sinergia de Valris", tecnica_2: "", expl_tec_1: "Si en el último turno perdiste una vida, ganas 3 puntos de vida", expl_tec_2: "", lore: "Nacido bajo el tercer eclipse del desierto, su magia honra pactos antiguos y como príncipe hechicero de las arenas, su poder no conquista: purifica, preserva y transforma.", img: "83.png" },
  { id: "RdC 84", nombre: "Mix", reino: "Daelum", clase: "Vampiro", fuerza: 2, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Ultimo hurto", tecnica_2: "", expl_tec_1: "Cuando es derrotada, roba una carta al azar de tu rival", expl_tec_2: "", lore: "Mix destila toxinas que alteran la voluntad y la carne mientras que su habilidad libera vapores encantados que confunden, seducen o destruyen según su capricho.", img: "84.png" },
  { id: "RdC 85", nombre: "Varkhan", reino: "Zelphyd", clase: "Vampiro", fuerza: 4, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Flujo sanguíneo", tecnica_2: "", expl_tec_1: "Si hay un sacerdote en tu campo de batalla tu rival pierde un punto de vida y tú ganas un punto de vida", expl_tec_2: "", lore: "El ascenso al poder suele estar sembrado de atrocidades, pero también hay belleza en el caos ... solo debes aprender a apreciarla.", img: "85.png" },
  { id: "RdC 86", nombre: "Celeste", reino: "Elenaria", clase: "Guerrero", fuerza: 4, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Rito del Ocaso", tecnica_2: "", expl_tec_1: "Tu rival intercambia su cementerio por su mazo y su mazo por su cementerio (Esta técnica tiene efecto si hay un sacerdote y un guerrero en el campo de batalla)", expl_tec_2: "", lore: "Nacida en las sombras del reino oscuro, fue la primera en desafiar su destino y abrazar la luz de Elenaria. -'Si la oscuridad nos creó, que la luz vea lo que somos capaces de deshacer'.", img: "86.png" },
  { id: "RdC 87", nombre: "Meleste", reino: "Elenaria", clase: "Sacerdote", fuerza: 5, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Rito del Alba", tecnica_2: "", expl_tec_1: "Tu intercambias tu cementerio por tu mazo y tu mazo por tu cementerio (Esta técnica tiene efecto si hay un guardián y un guerrero en el campo de batalla)", expl_tec_2: "", lore: "Criada en el mismo abismo que su hermana, siguió el rastro de luz que Celeste abrió en la oscuridad. -'Hermana, donde tu espada abre camino, mi magia lo ilumina o lo consume'.", img: "87.png" },
  { id: "RdC 88", nombre: "Talina", reino: "Ignis", clase: "Explorador", fuerza: 5, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Fiesta explosiva", tecnica_2: "", expl_tec_1: "Cuando entra al campo de batalla puedes ver las cartas de tu adversario y poner una en su mazo para que revuelva.", expl_tec_2: "", lore: "'¡Si no explota en colores, no cuenta como victory!' -Talina, exploradora alocada.", img: "88.png" },
  { id: "RdC 89", nombre: "Kraivus", reino: "Zelphyd", clase: "Guardián", fuerza: 8, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Última voluntad", tecnica_2: "", expl_tec_1: "Si lo juegas puedes decidir perder 1 punto de vida, si lo haces Kraivus obtiene Furia, Desafío, Firmeza", expl_tec_2: "", lore: "En sus ojos están grabados todos los caminos trazados por la antigua orden de la luz, pero el dolor y la deshonra nunca desaparecerán.", img: "89.png" },
  { id: "RdC 90", nombre: "Nairus", reino: "Cahl'ama", clase: "Guardián", fuerza: 6, rareza: "Rara", habilidad_1: "Firmeza", habilidad_2: "", tecnica_1: "Silencio sombrío", tecnica_2: "", expl_tec_1: "Juega una carta con una técnica que diga 'Derrotada' del cementerio de cualquier jugador.", expl_tec_2: "", lore: "Fue enterrado con mil nombres y mil maldiciones, pero las almas no lo olvidaron. Ahora, camina otra vez por el desierto, invocando a los que murieron ... y absorbiendo a los que lo negaron alguna vez.", img: "90.png" },
  { id: "RdC 91", nombre: "Ralya", reino: "Breesh", clase: "Hada", fuerza: 1, rareza: "Rara", habilidad_1: "Sigilo", habilidad_2: "", tecnica_1: "Susurro valeroso", tecnica_2: "", expl_tec_1: "Cuando es derrotada, si no hay más aliados en tu campo de batalla, derrota a todos los enemigos de tu rival", expl_tec_2: "", lore: "Guardiana del Bosque de los Ecos. Su magia florece al ritmo de los secretos que susurra la luz entre los árboles. Protege los recuerdos olvidados, convirtiéndolos en hechizos que sanan o condenan.", img: "91.png" },
  { id: "RdC 92", nombre: "Nelieri", reino: "Mo'lah", clase: "Pirata", fuerza: 5, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Copia pirata", tecnica_2: "", expl_tec_1: "Puedes revelar una carta de tu mano. Si lo haces, copia su técnica.", expl_tec_2: "", lore: "Criada entre pólvora y traiciones, Nelieri Drakborn heredó el timón ensangrentado de su padre ... pero no su alma. Ahora surca mares con una sed de conquista y es temida por quienes aún recuerdan su nombre como la Tempestad Roja.", img: "92.png" },
  { id: "RdC 93", nombre: "Nasin", reino: "Daelum", clase: "Erudito", fuerza: 7, rareza: "Rara", habilidad_1: "Dominante", habilidad_2: "", tecnica_1: "Grieta de Poibrik", tecnica_2: "", expl_tec_1: "Un rival descarta una carta. Si la carta tiene 4 de fuerza o más, el rival pierde 1 punto de vida", expl_tec_2: "", lore: "'¡No es veneno si te da superpoderes ... durante los primeros cinco minutos!' -Nasin, aprendiz rebelde de Laor.", img: "93.png" },
  { id: "RdC 94", nombre: "Kora", reino: "Breesh", clase: "Titán", fuerza: 3, rareza: "Rara", habilidad_1: "Desafío", habilidad_2: "", tecnica_1: "Indómito de Kora", tecnica_2: "", expl_tec_1: "Puedes descartar una carta de tu mano. Derrota todos los enemigos que compartan una habilidad con esta carta.", expl_tec_2: "", lore: "Un antiguo titán errante que protege los secretos de los bosques del reino. Su núcleo, codiciado por muchos, se dice que alberga el corazón de una diosa caída del Bosque de los Ecos.", img: "94.png" },
  { id: "RdC 95", nombre: "Marcus", reino: "Ignis", clase: "Explorador", fuerza: 6, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Inversión de fuego", tecnica_2: "", expl_tec_1: "Cuando Marcus gana una batalla descarta una carta de la mano de tu rival (Se activa solo si hay dos o más guerreros en el campo de batalla)", expl_tec_2: "", lore: "Aprendió a domar el fuego cuando su maestro lo abandono en el primer coliseo que vio. Ahora combate en arenas prohibidas, buscando reliquias que solo se revelan entre llamas y sangre.", img: "95.png" },
  { id: "RdC 96", nombre: "Tao'ai", reino: "Aystar", clase: "Bestia", fuerza: 5, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Furia salvaje", tecnica_2: "", expl_tec_1: "Cuando atacas, derrota a todos los rivales que tengan Sigilo y/o Letal", expl_tec_2: "", lore: "'¡Nadie volverá a encadenarme, nadie volverá a abandonarme y nadie volverá vivo!' -Tao'ai.", img: "96.png" },
  { id: "RdC 97", nombre: "Diana", reino: "Ventaris", clase: "Invocador", fuerza: 5, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Favor del viento", tecnica_2: "", expl_tec_1: "Cuando ataca, devuelve una carta de tu cementerio a tu mano", expl_tec_2: "", lore: "Por miedo, fue desterrada a las gargantas ventosas del Abismo del Sur ... En ese lugar solitario, Diana no se debilitó: creció.", img: "97.png" },
  { id: "RdC 98", nombre: "Kaelor", reino: "Aric", clase: "Golem", fuerza: 1, rareza: "Rara", habilidad_1: "Furia", habilidad_2: "", tecnica_1: "Presión rocosa", tecnica_2: "", expl_tec_1: "Cuando atacas tienes +8 de fuerza en este turno", expl_tec_2: "", lore: "'Tallado por manos que ya no existen, guarda en su corazón furia tectónica y luz prestada'. -Lavinia.", img: "98.png" },
  { id: "RdC 99", nombre: "Lit", reino: "Mo'lah", clase: "Invocador", fuerza: 3, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Retribución de Lit", tecnica_2: "", expl_tec_1: "Cuando es derrotada en combate, roba dos cartas al azar de la mano de tu rival", expl_tec_2: "", lore: "'Si temes ahogarte, retrocede ... mis criaturas no distinguen amigo de intruso'. Lit, la invocadora de Silente, canaliza las aguas antiguas que responden solo a su voluntad.", img: "99.png" },
  { id: "RdC 100", nombre: "Giaref", reino: "Aric", clase: "Guerrero", fuerza: 4, rareza: "Rara", habilidad_1: "Veloz", habilidad_2: "", tecnica_1: "Hacha de acero audaz", tecnica_2: "", expl_tec_1: "Si ganas la batalla, juegas otro turno después de este", expl_tec_2: "", lore: "Dicen que su fuerza no viene del cuerpo, sino de cada guerra que ha sobrevivido sin rendirse.", img: "100.png" },

  // --- HITOS (101 - 120) ---
  { id: "RdC 101", nombre: "Aeristra", reino: "Ventaris", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Otorga Veloz a los aliados que entren en juego.", expl_tec_2: "", lore: "", img: "101.png" },
  { id: "RdC 102", nombre: "Anerif", reino: "Cahl'ama", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Cegar no tiene efecto mientras esté en juego.", expl_tec_2: "", lore: "", img: "102.png" },
  { id: "RdC 103", nombre: "Forbice", reino: "Aystar", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Firmeza no tiene efecto mientras esté en juego.", expl_tec_2: "", lore: "", img: "103.png" },
  { id: "RdC 104", nombre: "Desfiladero Umbrio", reino: "Zelphyd", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Maldice con -2 de fuerza a enemigos que sufran Dominante mientras esté en juego.", expl_tec_2: "", lore: "", img: "104.png" },
  { id: "RdC 105", nombre: "Islas Serenas", reino: "Mo'lah", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Puedes robar 2 cartas en tu turno mientras esté en juego.", expl_tec_2: "", lore: "", img: "105.png" },
  { id: "RdC 106", nombre: "Runerra", reino: "Aric", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "El estratega obtienen +3 de vida.", expl_tec_2: "", lore: "", img: "106.png" },
  { id: "RdC 107", nombre: "Poibrik", reino: "Daelum", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Si tienes menos cartas en el campo de batalla, tus aliados obtienen Letal mientras esté en juego.", expl_tec_2: "", lore: "", img: "107.png" },
  { id: "RdC 108", nombre: "Laboratorios C.A.T", reino: "Ignis", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Al pasar 4 turnos, elimina la carta con mayor nivel de fuerza en cada uno de los campos de batalla mientras esté en juego.", expl_tec_2: "", lore: "", img: "108.png" },
  { id: "RdC 109", nombre: "Templo de Luminalia", reino: "Elenaria", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Sigilo no tiene efecto mientras esté juego.", expl_tec_2: "", lore: "", img: "109.png" },
  { id: "RdC 110", nombre: "Bosque de las Quimeras", reino: "Breesh", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Letal no tiene efecto mientras esté juego.", expl_tec_2: "", lore: "", img: "110.png" },
  { id: "RdC 111", nombre: "Valor de Luminis", reino: "Elenaria", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Todos tus aliados que entren al campo de batalla pertenecen a Elenaria", expl_tec_2: "", lore: "", img: "111.png" },
  { id: "RdC 112", nombre: "Cenizas de guerra", reino: "Ignis", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Al pasar 3 turnos, el aliado más fuerte cae en el cementerio", expl_tec_2: "", lore: "", img: "112.png" },
  { id: "RdC 113", nombre: "Senda de colmillos eternos", reino: "Aystar", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Las bestias y las cartas de Aystar obtienen 'DOMINANTE'", expl_tec_2: "", lore: "", img: "113.png" },
  { id: "RdC 114", nombre: "El valle de Prait", reino: "Cahl'ama", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Las cartas que tengan la palabra 'Derrotada' en su técnica, no se puede activar.", expl_tec_2: "", lore: "", img: "114.png" },
  { id: "RdC 115", nombre: "Ruinas de Verd", reino: "Breesh", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "El mandato de los hitos afectan a las dos direcciones", expl_tec_2: "", lore: "", img: "115.png" },
  { id: "RdC 116", nombre: "Profundidades de Laor", reino: "Daelum", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Puedes descartar una carta de tu mano, si lo haces pon una carta de tu cementerio a tu mano y otra en la parte baja de tu mazo. Termina tu turno", expl_tec_2: "", lore: "", img: "116.png" },
  { id: "RdC 117", nombre: "Aeral’Tha", reino: "Aric", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Aumenta en +3 el efecto de otorgar", expl_tec_2: "", lore: "", img: "117.png" },
  { id: "RdC 118", nombre: "Fosas del destino", reino: "Zelphyd", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Puedes descartar un aliado de tu campo de batalla, si lo haces puedes poner una carta desde el cementerio a tu mano con igual o menor fuerza que la carta descartada.", expl_tec_2: "", lore: "", img: "118.png" },
  { id: "RdC 119", nombre: "Ventailos", reino: "Ventaris", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Mientras esté en juego, no puedes revivir ni jugar cartas de los cementerios", expl_tec_2: "", lore: "", img: "119.png" },
  { id: "RdC 120", nombre: "Estrecho de Gaeltar", reino: "Mo'lah", clase: "Hito", fuerza: "", rareza: "Hito", habilidad_1: "", habilidad_2: "", tecnica_1: "", tecnica_2: "", expl_tec_1: "Las cartas que sean hundidas, van al cementerio", expl_tec_2: "", lore: "", img: "120.png" },

  // --- CARTAS LEGENDARIAS (121 - 130) ---
  { id: "RdC 121", nombre: "Mar'Glothar", reino: "Mo'lah", clase: "Dragón", fuerza: 8, rareza: "Legendaria", habilidad_1: "Sigilo", habilidad_2: "Firmeza", tecnica_1: "Intensidad del mar", tecnica_2: "Protector de lo profundo", expl_tec_1: "Cuando entra al campo de batalla, ciega a dos enemigos.", expl_tec_2: "Al terminar una batalla, ciega a un enemigo a elección.", lore: "Para algunos una leyenda, para el fondo del mar significa el orden y la paz. Se dice que Mar'Glothar existe desde la primera gota que tocó el mundo.", img: "121.png" },
  { id: "RdC 122", nombre: "Rokar", reino: "Aric", clase: "Golem", fuerza: 9, rareza: "Legendaria", habilidad_1: "Veloz", habilidad_2: "Dominante", tecnica_1: "Poder tectónico", tecnica_2: "Terremoto", expl_tec_1: "El hito de tu rival es destruido y pasa al cementerio.", expl_tec_2: "Tu rival tiene que descartar 3 cartas al cementerio.", lore: "El primer golem en evolucionar y tener su cuerpo definitivo. Rokar protege los tesoros y secretos ancestrales ocultos en las montañas.", img: "122.png" },
  { id: "RdC 123", nombre: "Val'kar", reino: "Cahl'ama", clase: "Guardián", fuerza: 7, rareza: "Legendaria", habilidad_1: "Veloz", habilidad_2: "Desafío", tecnica_1: "Flechas del desierto", tecnica_2: "Bendición del sol", expl_tec_1: "Si descartas una carta de tu mano, tu rival pierde una vida.", expl_tec_2: "Ganas 2 vidas y revive un aliado a elección del cementerio.", lore: "Bendecido con la resurrección y con el propósito de expandir el desierto y la gracia del sol. Val'Kar, es el defensor alado de su pueblo y el terror de la guerra.", img: "123.png" },
  { id: "RdC 124", nombre: "Pyroclast", reino: "Ignis", clase: "Titán", fuerza: 8, rareza: "Legendaria", habilidad_1: "Dominante", habilidad_2: "Firmeza", tecnica_1: "Mar de lava", tecnica_2: "Uno con el magma", expl_tec_1: "Hunde al enemigo con mayor nivel de fuerza.", expl_tec_2: "Elimina a un enemigo hundido a elección cada vez que gana una batalla.", lore: "Su presencia significa la destrucción de la vida por todo el odio con el que fue forjado por los antiguos reinos. Su calor derrite cualquier cosa al instante.", img: "124.png" },
  { id: "RdC 125", nombre: "Solarion", reino: "Ventaris", clase: "Domador", fuerza: 9, rareza: "Legendaria", habilidad_1: "Desafío", habilidad_2: "Veloz", tecnica_1: "Sin aire", tecnica_2: "Vendaval", expl_tec_1: "Silencia al siguiente enemigo que entre al campo de batalla.", expl_tec_2: "Tu rival debe colocar su mano en su mazo y revolver, luego sacar 3 cartas.", lore: "El primer maestro en dominar los aires y luchar contra los espíritus turbulentos. Los niños de Ventaris dicen que Solarion vive en las nubes y los protege del mal.", img: "125.png" },
  { id: "RdC 126", nombre: "Leonhart", reino: "Elenaria", clase: "Guerrero", fuerza: 8, rareza: "Legendaria", habilidad_1: "Furia", habilidad_2: "Desafío", tecnica_1: "Valor de Elenaria", tecnica_2: "Rugido de luz", expl_tec_1: "Leonhart gana +2 de fuerza por cada aliado de Elenaria que esté en el campo de batalla.", expl_tec_2: "Otorga +2 a todos los aliados que ya estén en el campo de batalla.", lore: "Su melena brilla como las estrellas en la noche más oscura. Su figura representa ferocidad y nobleza en su reino y para muchos el bien de este mundo en guerra.", img: "126.png" },
  { id: "RdC 127", nombre: "Thalyria", reino: "Zelphyd", clase: "Guerrero", fuerza: 10, rareza: "Legendaria", habilidad_1: "Toque mortal", habilidad_2: "Dominante", tecnica_1: "Sombra eterna", tecnica_2: "Miedo a la oscuridad", expl_tec_1: "Si es derrotada por primera vez, Thalyria regresa al mazo en vez del cementerio.", expl_tec_2: "Elimina al enemigo más débil en el campo de batalla.", lore: "Una de los comandantes más aterradoras de Zelphyd. Cuentan las historias que fue la aprendiz del primer rey guerrero y su sola presencia infunde terror.", img: "127.png" },
  { id: "RdC 128", nombre: "Viperion", reino: "Daelum", clase: "Bestia", fuerza: 9, rareza: "Legendaria", habilidad_1: "Toque mortal", habilidad_2: "Veloz", tecnica_1: "Profundidad venenosa", tecnica_2: "Instinto de locura", expl_tec_1: "Hunde a 2 enemigos a elección.", expl_tec_2: "Maldice con -3 a los próximos 2 enemigos que entren en el campo de batalla.", lore: "Las malas lenguas dicen que la toxicidad que existe en Daelum, proviene de las fauces de esta criatura ... así que ten mucho cuidado con ser corrompido por su saliva.", img: "128.png" },
  { id: "RdC 129", nombre: "Glaciar", reino: "Aystar", clase: "Titán", fuerza: 10, rareza: "Legendaria", habilidad_1: "Dominante", habilidad_2: "Furia", tecnica_1: "Protección de la nieve", tecnica_2: "Frío absoluto", expl_tec_1: "Cuando Glaciar entra al campo de batalla, tu rival descarta una carta de su mano.", expl_tec_2: "Hunde a todos los enemigos que estén en el campo de batalla.", lore: "Cada paso que da, causa las avalanchas más peligrosas para las personas fuera de Aystar. Glaciar fue creado para proteger la vida que nace en esta tierra.", img: "129.png" },
  { id: "RdC 130", nombre: "Gorak", reino: "Breesh", clase: "Bestia", fuerza: 9, rareza: "Legendaria", habilidad_1: "Firmeza", habilidad_2: "Furia", tecnica_1: "Fuerza bruta", tecnica_2: "Ego de rey", expl_tec_1: "Cada vez que derrote a un enemigo, Gorak gana +I de fuerza.", expl_tec_2: "Gorak es inmune a las técnicas que se jueguen en el campo de batalla rival.", lore: "Una criatura inocente que por sobrevivir a la locura del reino, tuvo que adaptarse hasta perder su nobleza.", img: "130.png" },

  ];